genvar way_idx;
generate
    for (way_idx = 0; way_idx < `L1D_WAYS; way_idx++)
    begin : hit_check_gen
        assign way_hit_oh[way_idx] = dt_request_paddr.tag == dt_tag[way_idx]
            && dt_valid[way_idx];
    end
endgenerate

// Treat a synchronized load as a cache miss the first time it occurs, because
// it needs to send it to the L2 cache to register it.
assign cache_hit = |way_hit_oh
    && (!sync_access_req || dd_load_sync_pending[dt_thread_idx])
    && dt_tlb_hit;

//
// Store alignment
//
idx_to_oh #(
    .NUM_SIGNALS(CACHE_LINE_WORDS),
    .DIRECTION("LSB0")
) idx_to_oh_cache_lane(
    .one_hot(cache_lane_mask),
    .index(cache_lane_idx));

always_comb
begin
    word_store_mask = 0;
    unique case (dt_instruction.memory_access_type)
        MEM_BLOCK, MEM_BLOCK_M:    // Block vector access
            word_store_mask = dt_mask_value;

        MEM_SCGATH, MEM_SCGATH_M:    // Scatter/Gather access
        begin
            if ((dt_mask_value & subcycle_mask) != 0)
                word_store_mask = cache_lane_mask;
            else
                word_store_mask = 0;
        end

        default:    // Scalar access
            word_store_mask = cache_lane_mask;
    endcase
end

// Endian swap vector data
genvar swap_word;
generate
    for (swap_word = 0; swap_word < CACHE_LINE_BYTES / 4; swap_word++)
    begin : swap_word_gen
        assign endian_twiddled_data[swap_word * 32+:8] = dt_store_value[swap_word][24+:8];
        assign endian_twiddled_data[swap_word * 32 + 8+:8] = dt_store_value[swap_word][16+:8];
        assign endian_twiddled_data[swap_word * 32 + 16+:8] = dt_store_value[swap_word][8+:8];
        assign endian_twiddled_data[swap_word * 32 + 24+:8] = dt_store_value[swap_word][0+:8];
    end
endgenerate

assign lane_store_value = dt_store_value[scgath_lane];

// byte_store_mask and dd_store_data.
always_comb
begin
    unique case (dt_instruction.memory_access_type)
        MEM_B, MEM_BX: // Byte
        begin
            dd_store_data = {CACHE_LINE_WORDS * 4{dt_store_value[0][7:0]}};
            case (dt_request_paddr.offset[1:0])
                2'd0: byte_store_mask = 4'b1000;
                2'd1: byte_store_mask = 4'b0100;
                2'd2: byte_store_mask = 4'b0010;
                2'd3: byte_store_mask = 4'b0001;
                default: byte_store_mask = 4'b0000;
            endcase
        end

        MEM_S, MEM_SX: // 16 bits
        begin
            dd_store_data = {CACHE_LINE_WORDS * 2{dt_store_value[0][7:0], dt_store_value[0][15:8]}};
            if (dt_request_paddr.offset[1] == 1'b0)
                byte_store_mask = 4'b1100;
            else
                byte_store_mask = 4'b0011;
        end

        MEM_L, MEM_SYNC: // 32 bits
        begin
            byte_store_mask = 4'b1111;
            dd_store_data = {CACHE_LINE_WORDS{dt_store_value[0][7:0], dt_store_value[0][15:8],
                dt_store_value[0][23:16], dt_store_value[0][31:24]}};
        end

        MEM_SCGATH, MEM_SCGATH_M:
        begin
            byte_store_mask = 4'b1111;
            dd_store_data = {CACHE_LINE_WORDS{lane_store_value[7:0], lane_store_value[15:8],
                lane_store_value[23:16], lane_store_value[31:24]}};
        end

        default: // Vector
        begin
            byte_store_mask = 4'b1111;
            dd_store_data = endian_twiddled_data;
        end
    endcase
end

// Generate store mask signals. word_store_mask corresponds to lanes,
// byte_store_mask corresponds to bytes within a word. byte_store_mask
// always has all bits set if word_store_mask has more than one bit set:
// either select some number of words within the cache line for
// a vector transfer or some bytes within a word for a scalar transfer.
genvar mask_idx;
generate
    for (mask_idx = 0; mask_idx < CACHE_LINE_BYTES; mask_idx++)
    begin : store_mask_gen
        assign dd_store_mask[mask_idx] = word_store_mask[
            (CACHE_LINE_BYTES - mask_idx - 1) / 4]
            & byte_store_mask[mask_idx & 3];
    end
endgenerate

oh_to_idx #(.NUM_SIGNALS(`L1D_WAYS)) encode_hit_way(
    .one_hot(way_hit_oh),
    .index(way_hit_idx));

sram_1r1w #(
    .DATA_WIDTH(CACHE_LINE_BITS),
    .SIZE(`L1D_WAYS * `L1D_SETS),
    .READ_DURING_WRITE("NEW_DATA")
) l1d_data(
    // Instruction pipeline access.
    .read_en(cache_hit && cached_load_req),
    .read_addr({way_hit_idx, dt_request_paddr.set_idx}),
    .read_data(dd_load_data),

    // Update from L2 cache interface
    .write_en(l2i_ddata_update_en),
    .write_addr({l2i_ddata_update_way, l2i_ddata_update_set}),
    .write_data(l2i_ddata_update_data),
    .*);

// cache_near_miss indicates a cache miss is occurring in the cycle this is
// filling the same line. If this suspends the thread, it will never
// receive a wakeup. Instead, roll the thread back and let it retry.
// Do not be set for a synchronized load, even if the data is in the L1
// cache: it must do a round trip to the L2 cache to latch the address.
assign cache_near_miss = !cache_hit
    && dt_tlb_hit
    && cached_load_req
    && |l2i_dtag_update_en_oh
    && l2i_dtag_update_set == dt_request_paddr.set_idx
    && l2i_dtag_update_tag == dt_request_paddr.tag
    && !sync_access_req
    && !any_fault;

assign dd_cache_miss = cached_load_req
    && !cache_hit
    && dt_tlb_hit
    && !cache_near_miss
    && !any_fault;
assign dd_cache_miss_addr = dcache_request_addr[31:CACHE_LINE_OFFSET_WIDTH];
assign dd_cache_miss_thread_idx = dt_thread_idx;
assign dd_cache_miss_sync = sync_access_req;

